/* animated node-network background (shared by the brand panel) */
function bergNet(c) {
  const x = c.getContext('2d');
  let W,
    H,
    nodes,
    DPR = Math.min(devicePixelRatio || 1, 2);
  const LINK = 150;
  function size() {
    const r = c.getBoundingClientRect();
    W = r.width;
    H = r.height;
    c.width = W * DPR;
    c.height = H * DPR;
    x.setTransform(DPR, 0, 0, DPR, 0, 0);
    const n = Math.min(70, Math.round(W * H / 13000));
    nodes = Array.from({
      length: n
    }, () => ({
      x: Math.random() * W,
      y: Math.random() * H,
      vx: (Math.random() - .5) * .34,
      vy: (Math.random() - .5) * .34,
      r: Math.random() * 1.6 + 1.3,
      gold: Math.random() > .8
    }));
  }
  size();
  addEventListener('resize', size);
  const pulses = [];
  setInterval(() => {
    if (!nodes || nodes.length < 2) return;
    const a = nodes[Math.random() * nodes.length | 0];
    let b = null,
      best = LINK;
    for (const m of nodes) {
      if (m === a) continue;
      const d = Math.hypot(m.x - a.x, m.y - a.y);
      if (d < best) {
        best = d;
        b = m;
      }
    }
    if (b) pulses.push({
      a,
      b,
      t: 0,
      sp: .013 + Math.random() * .012
    });
  }, 300);
  function tick() {
    x.clearRect(0, 0, W, H);
    for (let i = 0; i < nodes.length; i++) {
      const a = nodes[i];
      a.x += a.vx;
      a.y += a.vy;
      if (a.x < 0 || a.x > W) a.vx *= -1;
      if (a.y < 0 || a.y > H) a.vy *= -1;
      for (let j = i + 1; j < nodes.length; j++) {
        const b = nodes[j],
          d = Math.hypot(a.x - b.x, a.y - b.y);
        if (d < LINK) {
          const o = (1 - d / LINK) * .5;
          x.strokeStyle = 'rgba(120,150,186,' + o + ')';
          x.lineWidth = 1;
          x.beginPath();
          x.moveTo(a.x, a.y);
          x.lineTo(b.x, b.y);
          x.stroke();
        }
      }
    }
    for (const n of nodes) {
      x.beginPath();
      x.arc(n.x, n.y, n.r, 0, 7);
      x.fillStyle = n.gold ? 'rgba(214,180,108,1)' : 'rgba(160,180,205,.85)';
      x.fill();
      if (n.gold) {
        x.beginPath();
        x.arc(n.x, n.y, n.r + 4, 0, 7);
        x.fillStyle = 'rgba(203,168,92,.2)';
        x.fill();
      }
    }
    for (let i = pulses.length - 1; i >= 0; i--) {
      const p = pulses[i];
      p.t += p.sp;
      if (p.t >= 1) {
        pulses.splice(i, 1);
        continue;
      }
      const px = p.a.x + (p.b.x - p.a.x) * p.t,
        py = p.a.y + (p.b.y - p.a.y) * p.t;
      x.beginPath();
      x.arc(px, py, 3, 0, 7);
      x.fillStyle = 'rgba(220,186,110,1)';
      x.fill();
      x.beginPath();
      x.arc(px, py, 9, 0, 7);
      x.fillStyle = 'rgba(203,168,92,.26)';
      x.fill();
    }
    requestAnimationFrame(tick);
  }
  tick();
}
